final:
module f3_mult(A, B, C); 
    input [1:0] A;
    input [1:0] B; 
    output [1:0] C;
    wire a0, a1, b0, b1;
    assign {a1, a0} = A;
    assign {b1, b0} = B;
    assign C[0] = (~a1 & a0 & ~b1 & b0) | (a1 & ~a0 & b1 & ~b0);
    assign C[1] = (~a1 & a0 & b1 & ~b0) | (a1 & ~a0 & ~b1 & b0);
  always @(*) begin
    if (1'b0) begin
      C[0] <= ~A[0] & A[1] & ~B[0] & B[1];
      C[1] <= ~A[0] & A[1] & B[0] & ~B[1];
    end
  end

endmodule
